mapper.select:
SELECT u.username as username, u.real_name as student_name, c.class_name, r.title as report_title, e.completeness_score, e.specification_score, e.knowledge_score, e.total_score, e.evaluate_time FROM evaluation_record e LEFT JOIN training_report r ON e.report_id = r.id LEFT JOIN sys_user u ON r.student_id = u.id LEFT JOIN sys_class c ON u.class_id = c.id
u.class_id = #{classId}
ORDER BY e.total_score DESC
